import React, { useState, useEffect } from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Dashboard from './Pages/Dashboard';
import StudySession from './Pages/StudyRoom';
import Login from './Pages/Login';

function App() {
  // 1. Initialize state from localStorage
  const [schedule, setSchedule] = useState(() => {
    const saved = localStorage.getItem('studyPulse_Plan');
    return saved ? JSON.parse(saved) : null;
  });

  // 2. Automatically save to localStorage whenever the schedule updates
  useEffect(() => {
    if (schedule) {
      localStorage.setItem('studyPulse_Plan', JSON.stringify(schedule));
    }
  }, [schedule]);

  // 3. UPDATED: Function to update a specific day to 'completed'
  const markDayComplete = (dayNumber) => {
    setSchedule(prev => {
      // THE FIX: If there is no schedule yet, don't try to map it
      if (!prev) {
        console.warn("Attempted to mark a day complete, but no schedule exists.");
        return null;
      }

      return prev.map(item => 
        item.day === parseInt(dayNumber) ? { ...item, status: 'completed' } : item
      );
    });
  };

  return (
    <BrowserRouter>
      <Routes>
        <Route path="/login" element={<Login />} />
        <Route 
          path="/dashboard" 
          element={<Dashboard schedule={schedule} setSchedule={setSchedule} />} 
        />
        <Route 
          path="/study-session/:day" 
          element={<StudySession markDayComplete={markDayComplete} />} 
        />
        <Route path="/" element={<Login />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
